	import { useStore } from '$lib/tps/store.svelte.js';
	import { ARMOR_LEVEL_LABELS, VALIDATION_DEPARTMENTS } from '$lib/tps/constants.js';
	import { cn } from '$lib/utils.js';
	import * as Card from '$lib/components/ui/card/index.js';
